VALUES
  ('optometrist-moex-01974', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關測量氧氣穿過隱形眼鏡材質能力的評估，下列敘述何者正確？', '["傳氧性的檢測，需實際配戴隱形眼鏡後測量", "等效氧百分比的檢測，不需於配戴隱形眼鏡後測量", "溫度的增加，會使水凝膠鏡片的透氧率（Dk）降低", "水凝膠鏡片的透氧率與傳氧率成反比"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01975', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '若軟式隱形眼鏡的傳氧率（Dk/t）為60~75時，依Benjamin WJ和Karkkainen TR.等學者的研究，則氧氣 到達角膜的等效氧百分比（equivalentoxygenpercentage,EOP）範圍大約為多少？', '["16~18%", "6~11%", "＞85%", "55~73%"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01976', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關硬式透氣隱形眼鏡材質添加物的敘述，下列何者正確？', '["氟含量的增加可以增加鏡片的硬度", "N-乙烯基吡咯烷酮（N-vinylpyrrolidone）的添加，可增加材質強度", "矽含量的增加可以使鏡片沉澱物減少", "甲基丙烯酸的添加，可增加對水分子的親和力"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01977', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '對於硬式隱形眼鏡的使用順應性（compliance）不好，造成產生併發症的機會上升。下列關於順應性的敘 述，何者錯誤？', '["在使用隱形眼鏡之前，請先用肥皂和水洗手並澈底乾燥", "在隱形眼鏡盒裡，已用過的隱形眼鏡藥水每次都要丟掉，並使用新鮮隱形眼鏡藥水", "將鏡片放上眼睛表面後，將溶液從盒中傾倒，用消毒液沖洗隱形眼鏡盒並風乾。每週應一次或兩次使用 消毒液用指腹摩擦鏡片，對鏡片進行清潔以去除任何生物膜（biofilm），再用溶液沖洗", "若因配戴隱形眼鏡眼睛有乾澀不適感，應暫時性使用水龍頭水滋潤鏡片，以避免鏡片過乾"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01978', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關配戴隱形眼鏡的敘述，下列何者錯誤？', '["配戴後發現隱形眼鏡和角膜間有異物，可按住眼瞼將鏡片往內推，再以大量清水洗", "可使用微波爐消毒隱形眼鏡保存盒", "可利用taco試驗（tacotest）來測試鏡片是否內外顛倒", "配戴軟式隱形眼鏡的方式一般將鏡片的下緣沿著輪部下1-2公釐處45度角放入眼中"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01979', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '有關雙氧保養液（hydrogenperoxide）之敘述，下列何者正確？', '["雙氧保養液主要包含5%雙氧水以及中和錠（neutralizingtablet）", "中和錠需至少作用8小時後才能配戴隱形眼鏡", "使用雙氧保養液（hydrogenperoxide）的pH值大約是8左右", "雙氧保養液（hydrogenperoxide）是低張溶液（hypotonic）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01980', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '若一遠視硬式鏡片的後弧半徑維持不變，鏡片直徑變小，會造成：', '["鏡片重心（centerofgravity）往後移，鏡片滑動增加", "鏡片重心往後移，鏡片滑動減少", "鏡片重心往前移，鏡片滑動增加", "鏡片重心往前移，鏡片滑動減少"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01981', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '關於軟式隱形眼鏡保養清潔系統的比較，下列何者錯誤？', '["病人常常會有嚴重角膜破皮以及眼乾的情形，是因MPSs引起multipurposenonkeratitis", "病人有角膜破皮以及眼乾的情形，在換成雙氧系統後，症狀會改善", "軟式隱形眼鏡浸泡在MPSs溶液必須至少4-6小時後才可配戴", "雙氧系統的pH值通常在4左右"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01982', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '高透氧硬式隱形眼鏡驗配過程，以試片基弧7.80mm/鏡片光學區8.0mm/直徑9.2mm/度數 -3.50DS進行 配戴評估，螢光染色發現中心區表現為暗色區，旁中心區域與邊緣區並無界限，而且形成極寬螢光綠染區， 較恰當之試片調整為：', '["基弧改為7.90mm，鏡片光學區直徑不變", "基弧改為7.60mm，鏡片直徑不變", "鏡片直徑改為9.4mm，基弧改為8.0mm", "鏡片直徑改為9.0mm，基弧不變"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-01983', 'optometrist', 'optometrist-moex-109-28e89c47', 'sub-optometrist-05', NULL, 'single_choice', '硬式高透氧隱形眼鏡試片之右邊度數 -3.50DS/基弧7.70mm/鏡片光學區7.8mm/鏡片直徑9.2mm，左 邊度數 -3.00DS/基弧7.80mm/鏡片光學區7.8mm/鏡片直徑9.2mm，而戴鏡驗光最佳視力1.0的度數 兩邊皆 -2.00DS/-0.50DC×180。開立配鏡處方時，基弧皆選用7.80mm，則此訂片屈光度數為何？', '["右 -5.25DS，左 -5.00DS", "右 -6.25DS，左 -5.00DS", "右 -5.25DS，左 -5.25DS", "右 -6.25DS，左 -5.25DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "a1cbaa126f94", "answer_pdf_sha1": "06dd7a319b37", "source_family": "moex-gov-tw", "moex": {"exam_code": "109180", "c": "401", "s": "1504", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學與配鏡學", "year": "109", "exam_name": "109年專技人員高等考試建築師、32類科技師(含第二次食品技師)、大地工程技師考試分階段考試(第二階段考試)暨普通考試不動產經紀人、記帳士考...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL)
